    # Create a copy of the graph to avoid modifying the original
    graph_copy = graph_data.copy()

    # Find the EK_AGG_BLOCK node with the specified name
    agg_node_id = None
    for nid, ndata in graph_copy.nodes(data=True):
        if ndata.get('name') == 'ju1.a2.m3' and 'EK_AGG_BLOCK' in ndata.get('type', []):
            agg_node_id = nid
            break

