            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }
        return return_object

    # Helper to compute total physical capacity for a given node
    def compute_capacity(start_node):
        total = 0
        stack = [start_node]
        visited = set()
        while stack:
            current = stack.pop()
            if current in visited:
                continue
            visited.add(current)
            cdata = graph_copy.nodes[current]
            if 'EK_PORT' in cdata.get('type', []):
                total += cdata.get('physical_capacity_bps', 0)
            # Traverse children via RK_CONTAINS edges
            for _, child, edata in graph_copy.out_edges(current, data=True):
